        },
        "佐藤樱子（照片中）": {
          "character_id": "SAKURA_CHILD",
          "name": "佐藤樱子",
          "costume": "照片中固定为藏青色学生校服、白色衬衫、朴素学生发型",
          "source": "shot_explicit",
          "is_canonical": false,
          "costume_id": "SAKURA_PHOTO_UNIFORM_EP02",
          "applies_to_shots": [
            "SH13"
